export function createPelicanSdf(canvas) {
  const gl = canvas.getContext('webgl2');
  if (!gl) throw new Error('WebGL2 unavailable');
  canvas.tabIndex = 1;
  let yaw = 0, pitch = 0.3, distance = 15;
